/* eslint-disable unicorn/no-null */
import './Rating.scss';

import { Typography } from ':components/Typography';
import { classNames } from ':helpers/classnames';
import type { ReactNode } from 'react';
import React, { useState } from 'react';

import { RatingItem } from './items/RatingItem';
import { RatingItemNumber } from './items/RatingItemNumber';
import { RatingItemStar } from './items/RatingItemStar';
import type { RatingProps } from './Rating.types';

export const Rating: React.FC<RatingProps> = ({
	item = 'star',
	minIndex = 1,
	maxIndex = 5,
	onChange,
	onHover,
	value,
	caption,
	score,
	className,
	disabled,
	readonly,
	...props
}) => {
	const [hoverIndex, setHoverIndex] = useState<number | null>(null);

	const renderItem = (index: number): ReactNode => {
		if (item === 'star') {
			const isSelected = (hoverIndex || value) >= index;
			return <RatingItemStar selected={isSelected} />;
		}
		if (item === 'number') {
			const isSelected = value === index;
			return <RatingItemNumber value={index} selected={isSelected} />;
		}
		if (typeof item === 'function') {
			return item(index);
		}
	};

	const handleMouseLeave = event => {
		setHoverIndex(null);
		onHover?.(null);
	};

	const handleMouseEnter = index => {
		setHoverIndex(index);
		onHover?.(index);
	};

	const items = () =>
		Array.from({ length: maxIndex - minIndex + 1 }, (_, index) => minIndex + index).map(num => (
			<RatingItem key={num} onChange={onChange} onMouseEnter={() => handleMouseEnter(num)} index={num}>
				{renderItem(num)}
			</RatingItem>
		));

	return (
		<div
			data-testid="Rating"
			className={classNames(
				'dsb_rating',
				className,
				disabled && 'dsb_rating-disabled',
				readonly && 'dsb_rating-readonly',
			)}
			{...props}
			onMouseLeave={handleMouseLeave}
		>
			{score && (
				<div className={classNames('dsb_rating__score')}>
					{React.isValidElement(score) ? (
						score
					) : (
						<Typography className="dsb_rating__score-text" variant="h4">
							{score}
						</Typography>
					)}
				</div>
			)}
			<div
				className={classNames(
					'dsb_rating__select',
					item === 'star' && 'dsb_rating__select-star',
					item === 'number' && 'dsb_rating__select-number',
				)}
			>
				{items()}
			</div>
			{caption && (
				<div className="dsb_rating__caption">
					<Typography variant="body3" className="dsb_rating__caption-left" inactive>
						{caption?.left}
					</Typography>
					<Typography variant="body3" className="dsb_rating__caption-right" inactive>
						{caption?.right}
					</Typography>
				</div>
			)}
		</div>
	);
};
